(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn25"],{8944:function(n,r){n.exports='### MongoDB创建用户\r\n\r\n 1.创建管理员\r\n ```s\r\n # 创建（切换到）admin数据库\r\n use admin\r\n # 创建一个帐号\r\n db.createUser({user:"admin",pwd:"admin",roles:["root"]})\r\n\r\n ```\r\n 2.授权认证\r\n ```s\r\n # 对帐号进行认证\r\n db.auth("admin","admin")\r\n ```\r\n 3.给使用的数据库添加用户\r\n ```s\r\n# 创建（切换到）test数据库\r\n use test\r\n # 给test数据库创建一个用户\r\n db.createUser({user:"root",pwd:"123456",roles:[{role:"dbOwner",db:"test"}]})\r\n ```\r\n4.通过--auth启动mongoDB\r\n ```s\r\n mongod -f /Users/zhangyu/server/mongo/etc/mongo.conf --auth\r\n ```\r\n\r\n ### MongoDB基本语法\r\n ![avatar](https://raw.githubusercontent.com/sunny586/sunny586.github.io/master/images/mongo/mgdb.png)\r\n + 插入文档\r\n + 更新文档\r\n + 删除文档\r\n + 查询文档\r\n\r\n```s\r\n# 查看数据库\r\nshow dbs\r\n# 创建数据库\r\nuse demo\r\n# 创建一个集合（表）\r\ndb.createCollection("user")\r\n# 创建一个集合（表），并插入一条数据\r\ndb.users.insert({id:123,name:"hello"})\r\n# 删除一个集合\r\ndb.user.drop()\r\n# 查看集合（表）\r\nshow conllections\r\n# 删除数据库\r\ndb.dropDatabase()\r\n# 查看数据库\r\ndb.user.find() # db.user.find().pretty() (格式化)\r\n# 查询第一条数据\r\ndb.user.findOne()\r\n# 更新一条数据\r\ndb.user.update({userName:"jack"},{$set:{userAge:30}})\r\n# 更新一条子文档\r\ndb.user.update({userName:"jack"},{$set:{"class.name":\'baidu-test\'}})\r\n# 查询文档\r\ndb.user.find({userName:\'jack\'})\r\n# 查询子文档\r\ndb.user.find({\'class.name\':\'baidu\'})\r\n# 查询年龄大于40的文档\r\ndb.user.find({userAge:{$gt:40}})\r\n# 查询年龄小于40的文档\r\ndb.user.find({userAge:{$lt:40}})\r\n# 查询年龄等于40的文档\r\ndb.user.find({userAge:{$eq:40}})\r\n# 查询年龄大于等于40的文档\r\ndb.user.find({userAge:{$gte:40}})\r\n# 删除一条文档\r\ndb.user.remove({userId:101})\r\n```\r\n### 表数据设计和插入\r\n\r\n1.手动插入\r\n```s\r\n# 创建数据库db_demo\r\nuse db_demo\r\n# 创建goods集合（表），并插入一条数据\r\ndb.goods.insert({"id":\'1001\',name:\'zhangsan\',address:\'深圳\'})\r\n```\r\n2.文件导入\r\n```s\r\n# 创建一个空集合\r\ndb.createCollection("users")\r\n# 用客户端工具将数据文件导入即可\r\n用mongohub客户端导入数据\r\n```\r\n3.用MongoDB终端进行导入\r\n```s\r\n# db_demo是数据库名称\r\n# users是集合名称（表）\r\n# /Users/zhangyu/Desktop/dumall-users.是要导入的文件\b的目录\r\nmongoimport -d db_demo -c users --file /Users/zhangyu/Desktop/dumall-users.\r\n```\r\n\r\n### 搭建基于Express框架的运行环境\r\n\r\n安装express generator生成器\r\n```s\r\n# 全局安装express-generator生成器\r\nnpm install -g express-generator\r\n# 查看express版本\r\nexpress --version\r\n```\r\n通过生成器自动创建项目\r\n```s\r\n# 生成一个项目\r\nexpress server\r\n```\r\n配置分析\r\n```s\r\n# express默认使用jade，可以修改成html\r\napp.set(\'views\', path.join(__dirname, \'views\'));\r\napp.engine(\'.html\',ejs.__express);\r\napp.set(\'view engine\', \'html\');\r\n```\r\n\r\n### Node的启动和调试方式\r\n\r\n通过node命令启动\r\n```s\r\nnode server/bin/www\r\n```\r\npm2启动\r\n```s\r\n# 全局安装pm2 \r\nnpm install pm2 -g\r\n# 启动服务\r\npm2 start server/bin/www\r\n# 停掉服务\r\npm2 stop server/bin/www\r\n# 停掉所有服务\r\npm2 stop all\r\n# 查看启动的服务\r\npm2 list\r\n# 查看日志\r\npm2 log\r\n```\r\n\r\n### 基于Express开发后台接口\r\n\r\n安装Mongose\r\n```s\r\n# npm方式安装\r\nnpm install mongoose --save \r\n# yarn 方式安装\r\nyarn add mongoose\r\n```\r\n创建model\r\n```js\r\n// 获取mongoose对象\r\nvar mongoose = require(\'mongoose\');\r\n// 获取Schema对象\r\nvar Schema = mongoose.Schema;\r\n// 创建一个Schema\r\nvar produtSchema = new Schema({\r\n  "productId": {\r\n    type: String\r\n  },\r\n  "productName": String,\r\n  "salePrice": Number,\r\n  "productNum": Number,\r\n  "checked": String,\r\n  "productImage": String\r\n});\r\n// 导出Schema,并关联goods表\r\nmodule.exports = mongoose.model(\'Good\', produtSchema);\r\n```\r\n创建路由\r\n```js\r\nvar express = require(\'express\');\r\nvar router = express.Router();\r\nvar mongoose = require(\'mongoose\');\r\nvar Goods = require(\'../models/goods\');\r\n//连接MongoDB数据库\r\nmongoose.connect(\'mongodb://127.0.0.1:27017/dumall\');\r\n// connected 链接成功\r\nmongoose.connection.on("connected", function () {\r\n  console.log("MongoDB connected success.")\r\n});\r\n// error 链接失败\r\nmongoose.connection.on("error", function () {\r\n  console.log("MongoDB connected fail.")\r\n});\r\n// disconnected 断开链接\r\nmongoose.connection.on("disconnected", function () {\r\n  console.log("MongoDB connected disconnected.")\r\n});\r\n// 创建路由\r\nrouter.get(\'/\', function (req, res, next) {\r\n  Goods.find({}, function (err, doc) {\r\n    if (err) {\r\n      res.json({\r\n        status: \'1\',\r\n        msg: err.message\r\n      })\r\n    } else {\r\n      res.json({\r\n        status: \'0\',\r\n        msg: \'ok\',\r\n        result: {\r\n          count: doc.length,\r\n          list: doc\r\n        }\r\n      })\r\n    }\r\n  })\r\n});\r\nmodule.exports = router;\r\n```\r\n[范例](#/learn/expressapi)'},e08c:function(n,r,e){"use strict";e.r(r);var s=function(){var n=this,r=n.$createElement,s=n._self._c||r;return s("markdown",{attrs:{source:e("8944")}})},o=[],t=e("2877"),d={},a=Object(t["a"])(d,s,o,!1,null,null,null);a.options.__file="mongodb.vue";r["default"]=a.exports}}]);